@startuml
package index {
    class Index {
        interface index(String term, File) -> void
        interface search(String term) -> Set<File>
        interface isPersistent() -> boolean
    }

    class PersistentIndex {
        interface persist() -> void
        interface restore() -> boolean
    }

    class InMemoryMapIndex {
        attribute index: Map<String, Set<File>>
    }

    class MapIndex {
        attribute indexFile: File
        interface MapIndex(File, :Index)
    }
}

package fulltextsearch {
    package index
}

package ic6821 {
    package fulltextsearch
}

